/**
 * Send a notification payload through the appropriate adapter.
 * Checks user preferences before sending if a PreferencesService is configured.
 * Payloads with metadata.userId will be checked against that user's preferences.
 */
async send(payload: NotificationPayload): Promise<NotificationResult> {
  // Check user preferences if available
  if (this.preferencesService && payload.metadata?.['userId']) {
    const userId = payload.metadata['userId'] as string;
    if (!this.preferencesService.shouldSendEmail(userId, payload.type)) {
      const result: NotificationResult = {
        success: true,
        notificationId: payload.id,
        channel: payload.channel,
        deliveredAt: new Date(),
      };
      this.logger.info(`Notification ${payload.id} skipped — user ${userId} opted out of ${payload.type}`);
      return result;
    }
  }

  const adapter = this.adapters.get(payload.channel);

  if (!adapter) {
    const result: NotificationResult = {
      success: false,
      notificationId: payload.id,
      channel: payload.channel,
      error: `No adapter registered for channel: ${payload.channel}`,
      deliveredAt: new Date(),
    };
    const errorMsg = `No adapter registered for channel: ${payload.channel}`;
    this.records.push({ payload, result });
    this.logger.warn(errorMsg);
    return result;
  }

  const result = await adapter.send(payload);
  this.records.push({ payload, result });

  if (result.success) {
    this.logger.info(`Notification ${payload.id} sent via ${payload.channel} to ${payload.recipient}`);
  } else {
    this.logger.error(`Notification ${payload.id} failed via ${payload.channel}: ${result.error}`);
  }

  return result;
}

