import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { PreferencesRepository } from '../../src/repositories/preferences.repository.js';
import {
  PreferencesService,
  resetPreferencesIdCounter,
} from '../../src/services/preferences.service.js';
import { DEFAULT_EMAIL_PREFERENCES } from '../../src/models/user-preferences.js';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import { EmailAdapter } from '../../src/adapters/email.adapter.js';
import type { OrderCreatedEvent, UserCreatedEvent } from '../../src/events/event-types.js';

describe('PreferencesService', () => {
  let db: Database;
  let preferencesRepo: PreferencesRepository;
  let service: PreferencesService;

  beforeEach(() => {
    db = new Database();
    preferencesRepo = new PreferencesRepository(db);
    service = new PreferencesService(preferencesRepo);
    resetPreferencesIdCounter();
  });

  describe('getPreferences', () => {
    it('should return default preferences when none exist', () => {
      const prefs = service.getPreferences('user-1');

      expect(prefs.userId).toBe('user-1');
      expect(prefs.email.enabled).toBe(true);
      expect(prefs.email.frequency).toBe('immediate');
      expect(prefs.email.subscribedTypes).toEqual(DEFAULT_EMAIL_PREFERENCES.subscribedTypes);
    });

    it('should return saved preferences when they exist', () => {
      service.updateEmailPreferences('user-1', {
        frequency: 'daily_digest',
      });

      const prefs = service.getPreferences('user-1');
      expect(prefs.email.frequency).toBe('daily_digest');
      expect(prefs.email.enabled).toBe(true);
    });
  });

  describe('updateEmailPreferences', () => {
    it('should create preferences on first update', () => {
      const prefs = service.updateEmailPreferences('user-1', {
        enabled: false,
      });

      expect(prefs.id).toBe('pref-0001');
      expect(prefs.userId).toBe('user-1');
      expect(prefs.email.enabled).toBe(false);
      expect(prefs.email.frequency).toBe('immediate');
    });

    it('should update existing preferences', () => {
      service.updateEmailPreferences('user-1', { enabled: true });
      const updated = service.updateEmailPreferences('user-1', {
        frequency: 'weekly_digest',
      });

      expect(updated.email.frequency).toBe('weekly_digest');
      expect(updated.email.enabled).toBe(true);
    });

    it('should update subscribed types', () => {
      const prefs = service.updateEmailPreferences('user-1', {
        subscribedTypes: ['order_confirmation', 'welcome'],
      });

      expect(prefs.email.subscribedTypes).toEqual(['order_confirmation', 'welcome']);
    });

    it('should generate sequential IDs', () => {
      const p1 = service.updateEmailPreferences('user-1', {});
      const p2 = service.updateEmailPreferences('user-2', {});

      expect(p1.id).toBe('pref-0001');
      expect(p2.id).toBe('pref-0002');
    });

    it('should not generate new ID when updating existing preferences', () => {
      const created = service.updateEmailPreferences('user-1', { enabled: true });
      const updated = service.updateEmailPreferences('user-1', { enabled: false });

      expect(updated.id).toBe(created.id);
    });

    it('should preserve other fields when partially updating', () => {
      service.updateEmailPreferences('user-1', {
        frequency: 'daily_digest',
        subscribedTypes: ['order_confirmation'],
      });

      const updated = service.updateEmailPreferences('user-1', {
        enabled: false,
      });

      expect(updated.email.enabled).toBe(false);
      expect(updated.email.frequency).toBe('daily_digest');
      expect(updated.email.subscribedTypes).toEqual(['order_confirmation']);
    });
  });

  describe('shouldSendEmail', () => {
    it('should return true by default for all notification types', () => {
      expect(service.shouldSendEmail('user-1', 'order_confirmation')).toBe(true);
      expect(service.shouldSendEmail('user-1', 'welcome')).toBe(true);
      expect(service.shouldSendEmail('user-1', 'order_status_update')).toBe(true);
      expect(service.shouldSendEmail('user-1', 'account_updated')).toBe(true);
    });

    it('should return false when email is disabled', () => {
      service.updateEmailPreferences('user-1', { enabled: false });

      expect(service.shouldSendEmail('user-1', 'order_confirmation')).toBe(false);
    });

    it('should return false for unsubscribed notification types', () => {
      service.updateEmailPreferences('user-1', {
        subscribedTypes: ['order_confirmation'],
      });

      expect(service.shouldSendEmail('user-1', 'order_confirmation')).toBe(true);
      expect(service.shouldSendEmail('user-1', 'welcome')).toBe(false);
    });
  });
});

describe('NotificationService with preferences', () => {
  let db: Database;
  let eventBus: EventBus;
  let notificationService: NotificationService;
  let emailAdapter: EmailAdapter;
  let preferencesService: PreferencesService;

  beforeEach(() => {
    db = new Database();
    eventBus = new EventBus();
    notificationService = new NotificationService(eventBus);
    emailAdapter = new EmailAdapter();
    notificationService.registerAdapter(emailAdapter);
    resetNotificationIdCounter();
    resetPreferencesIdCounter();

    const preferencesRepo = new PreferencesRepository(db);
    preferencesService = new PreferencesService(preferencesRepo);
    notificationService.setPreferencesService(preferencesService);
  });

  it('should send notification when user has default preferences', async () => {
    const event: OrderCreatedEvent = {
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
        total: 10,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    const emails = emailAdapter.getSentEmails();
    expect(emails).toHaveLength(1);
    expect(emails[0]?.to).toBe('alice@example.com');
  });

  it('should skip notification when user has disabled email', async () => {
    preferencesService.updateEmailPreferences('user-1', { enabled: false });

    const event: OrderCreatedEvent = {
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
        total: 10,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    const emails = emailAdapter.getSentEmails();
    expect(emails).toHaveLength(0);
  });

  it('should skip notification when user unsubscribed from type', async () => {
    preferencesService.updateEmailPreferences('user-1', {
      subscribedTypes: ['welcome'],
    });

    const event: OrderCreatedEvent = {
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
        total: 10,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    const emails = emailAdapter.getSentEmails();
    expect(emails).toHaveLength(0);
  });

  it('should send welcome email when user is subscribed to it', async () => {
    const event: UserCreatedEvent = {
      type: 'user:created',
      user: {
        id: 'user-1',
        name: 'Bob',
        email: 'bob@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    const emails = emailAdapter.getSentEmails();
    expect(emails).toHaveLength(1);
    expect(emails[0]?.subject).toBe('Welcome to TaskFlow Pro');
  });

  it('should still send notifications without preferences service configured', async () => {
    const plainService = new NotificationService(new EventBus());
    const adapter = new EmailAdapter();
    plainService.registerAdapter(adapter);

    const result = await plainService.send({
      id: 'test-1',
      type: 'order_confirmation',
      channel: 'email',
      recipient: 'test@example.com',
      subject: 'Test',
      body: 'Test body',
      priority: 'normal',
      createdAt: new Date(),
      metadata: { userId: 'user-1' },
    });

    expect(result.success).toBe(true);
    expect(adapter.getSentEmails()).toHaveLength(1);
  });
});
